1	export type Cell = [number, number];
2	
3	const isNeighbor = ([r, c]: Cell, [targetR, targetC]: Cell): boolean =>
4	  Math.abs(r - targetR) <= 1 && Math.abs(c - targetC) <= 1 && !(r === targetR && c === targetC);
5	
6	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
7	  cells.filter((other) => isNeighbor(other, cell)).length;
8	
9	const getDeadNeighborCandidates = (cells: Cell[]): Cell[] => {
10	  const liveSet = new Set(cells.map(([r, c]) => `${r},${c}`));
11	  const candidates = new Map<string, Cell>();
12	  for (const [r, c] of cells) {
13	    for (let dr = -1; dr <= 1; dr++) {
14	      for (let dc = -1; dc <= 1; dc++) {
15	        if (dr === 0 && dc === 0) continue;
16	        const key = `${r + dr},${c + dc}`;
17	        if (!liveSet.has(key)) {
18	          candidates.set(key, [r + dr, c + dc]);
19	        }
20	      }
21	    }
22	  }
23	  return Array.from(candidates.values());
24	};
25	
26	export function nextGeneration(cells: Cell[]): Cell[] {
27	  const survivors = cells.filter((cell) => {
28	    const neighborCount = countNeighbors(cell, cells);
29	    return neighborCount === 2 || neighborCount === 3;
30	  });
31	  const newborns = getDeadNeighborCandidates(cells).filter(
32	    (cell) => countNeighbors(cell, cells) === 3
33	  );
34	  return [...survivors, ...newborns];
35	}
