2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has exactly 2 live neighbors", () => {
15	    expect(nextGeneration([[0, 1], [1, 1], [2, 1]])).toEqual([[1, 1], [1, 0], [1, 2]]);
16	  });
17	  it("should keep a live cell alive when it has exactly 3 live neighbors", () => {
18	    // (1,0) has 3 neighbors: (0,0),(2,0),(1,1); all cells have 2 or 3 neighbors and survive
19	    // dead cells (0,1),(1,-1),(2,1) each have exactly 3 live neighbors and are born
20	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toEqual([[0, 0], [1, 0], [2, 0], [1, 1], [0, 1], [1, -1], [2, 1]]);
21	  });
22	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
23	    // center (1,1) has 5 neighbors: (0,0),(1,0),(2,0),(0,1),(2,1) - dies
24	    // (1,0) also has 5 neighbors - dies; others have 3 neighbors - survive
25	    // dead cells (1,-1) and (1,2) each have exactly 3 live neighbors and are born
26	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [2, 1], [1, 1]])).toEqual([[0, 0], [2, 0], [0, 1], [2, 1], [1, -1], [1, 2]]);
27	  });
28	  it("should make a dead cell alive when it has exactly 3 live neighbors (reproduction)", () => {
29	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
30	  });
31	  it("should keep a 2x2 block unchanged (still life)", () => {
32	    expect(nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
33	  });
34	});
